{
  "success": true,
  "data": {
    "train": {
      "formation": "SF10",
      "totalCars": 10,
      "capacityPerCar": 200
    },
    "occupancy": {
      "lowThreshold": 0.4,
      "normalThreshold": 0.7,
      "highThreshold": 0.9,
      "fullThreshold": 1.0
    },
    "cameras": [
      { "id": "car01_cam01", "type": "cabin", "zone": "car_1", "carMapping": 1, "status": "online" },
      { "id": "car01_cam02", "type": "cabin", "zone": "car_1", "carMapping": 1, "status": "online" },
      ...
    ],
    "ai": {
      "model": "YOLO11s",
      "confidence": 0.5,
      "imageSize": 640
    }
  }
